import React, { useState, useEffect } from 'react';
import {
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  Modal,
  Box,
  Typography,
} from '@mui/material';
import ProductTypeForm from './ProductTypeForm';
import { getProductTypes, deleteProductType } from '../services/api';

const ProductTypeTable = () => {
  const [productTypes, setProductTypes] = useState([]);
  const [open, setOpen] = useState(false);
  const [editing, setEditing] = useState(null);

  useEffect(() => {
    fetchProductTypes();
  }, []);

  const fetchProductTypes = async () => {
    try {
      const response = await getProductTypes();
      setProductTypes(response.data);
    } catch (error) {
      console.error('Error fetching product types:', error);
    }
  };

  const handleOpen = (item = null) => {
    setEditing(item);
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
    setEditing(null);
  };

  const handleSave = () => {
    fetchProductTypes();
    handleClose();
  };

  const handleDelete = async (id) => {
    try {
      await deleteProductType(id);
      fetchProductTypes();
    } catch (error) {
      console.error('Error deleting product type:', error);
    }
  };

  return (
    <div>
      <Button variant="contained" onClick={() => handleOpen()}>
        New
      </Button>
      <TableContainer component={Paper} style={{ marginTop: 20 }}>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Display Name</TableCell>
              <TableCell>API Name</TableCell>
              <TableCell>Asset Type</TableCell>
              <TableCell>Asset Category</TableCell>
              <TableCell>Description</TableCell>
              <TableCell>Actions</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {productTypes.map((item) => (
              <TableRow key={item.id}>
                <TableCell>{item.display_name}</TableCell>
                <TableCell>{item.api_name}</TableCell>
                <TableCell>{item.asset_type}</TableCell>
                <TableCell>{item.asset_category_type}</TableCell>
                <TableCell>{item.description}</TableCell>
                <TableCell>
                  <Button onClick={() => handleOpen(item)}>Edit</Button>
                  <Button onClick={() => handleDelete(item.id)}>Delete</Button>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
      <Modal open={open} onClose={handleClose}>
        <Box
          sx={{
            position: 'absolute',
            top: '50%',
            left: '50%',
            transform: 'translate(-50%, -50%)',
            width: 400,
            bgcolor: 'background.paper',
            boxShadow: 24,
            p: 4,
          }}
        >
          <Typography variant="h6" component="h2">
            {editing ? 'Edit Product Type' : 'New Product Type'}
          </Typography>
          <ProductTypeForm
            editing={editing}
            onSave={handleSave}
            productTypes={productTypes}
          />
        </Box>
      </Modal>
    </div>
  );
};

export default ProductTypeTable;
